	var targetType = TypedArrayElementType(target); 

	var targetElementSize = TypedArrayElementSize(target); 

	var targetByteOffset = typedArrayByteOffset(target); 

	var srcType = TypedArrayElementType(source); 

	var srcElementSize = TypedArrayElementSize(source); 

