	var sourceContentType = whichSource === 'BigInt64Array' || whichSource === 'BigUint64Array' ? 'BIGINT' : 'NUMBER';
	if (targetContentType !== sourceContentType) {
		throw new $TypeError('source and target must have the same content type'); 
	}

